#include <bits/stdc++.h>
using namespace std;
const int N=200000;
int n,ans[N];
struct node
{
    int num,id;
} a[N],b[N],c[N];
bool fun(node x,node y)
{
    return x.num>y.num;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    memset(ans,0x3f,sizeof(ans));
    for(int i=1;i<=n;i++)
    {
        cin>>a[i].num>>b[i].num>>c[i].num;
        a[i].id=b[i].id=c[i].id=i;
    }
    sort(a+1,a+1+n,fun);
    sort(b+1,b+1+n,fun);
    sort(c+1,c+1+n,fun);
    for(int i=1;i<=n;i++)
    {
        int a2=i,b2=i,c2=i;
        for(int j=i-1;j>0&&a[j].num==a[i].num;j--) a2--;
        for(int j=i-1;j>0&&b[j].num==b[i].num;j--) b2--;
        for(int j=i-1;j>0&&c[j].num==c[i].num;j--) c2--;
        ans[a[i].id]=min(a2,ans[a[i].id]);
        ans[b[i].id]=min(b2,ans[b[i].id]);
        ans[c[i].id]=min(c2,ans[c[i].id]);
    }
    for(int i=1;i<=n;i++) cout<<ans[i]<<'\n';
    return 0;
}
